/**
 * @return [0] = read end, [1] = write end
 */
public static FileDescriptor[] pipe() throws IOException {
    long res = newPipe();
    if (res < 0) {
        throw newIOException("newPipe", (int) res);
    }
    return new FileDescriptor[]{new FileDescriptor((int) (res >>> 32)), new FileDescriptor((int) res)};
}
```

